RETURN BOOLEAN IS
v_i NUMBER;
BEGIN
IF p_num < 2 THEN
RETURN FALSE;
END IF;
v_i := 2;
WHILE v_i <= SQRT(p_num) LOOP
IF MOD(p_num, v_i) = 0 THEN
RETURN FALSE; -- tiene un divisor → no es primo
END IF;
v_i := v_i + 1;
END LOOP;
RETURN TRUE;
END;
