NodoD actual = cabeza;
while (actual != null && actual.dato != valor) {
actual = actual.siguiente; // buscar el nodo
}
if (actual == null) return; // no encontrado
if (actual.anterior != null) // reenlazar el anterior
actual.anterior.siguiente = actual.siguiente;
else
cabeza = actual.siguiente; // era la cabeza
if (actual.siguiente != null) // reenlazar el siguiente
actual.siguiente.anterior = actual.anterior;
}
