import java.util.*;
// Interfaz Observador
interface Observador {
void actualizar(String mod, String nuevaVersion);
}
// Interfaz Sujeto (Observable)
interface Sujeto {
void suscribir(Observador o);
void desuscribir(Observador o);
void notificar(String nuevaVersion);
}
// Sujeto concreto
class Mod implements Sujeto {
private String nombre;
private List<Observador> suscriptores = new ArrayList<>();
public Mod(String nombre) { this.nombre = nombre; }
public void suscribir(Observador o) { suscriptores.add(o); }
public void desuscribir(Observador o) { suscriptores.remove(o); }
public void notificar(String nuevaVersion) {
for (Observador o : suscriptores) o.actualizar(nombre, nuevaVersion);
}
// Disparador del evento
public void publicarVersion(String version) {
System.out.println("Mod " + nombre + " publicó versión " + version);
notificar(version);
}
}
// Observador concreto
class UsuarioSuscriptor implements Observador {
private String nombre;
public UsuarioSuscriptor(String nombre) { this.nombre = nombre; }
public void actualizar(String mod, String nuevaVersion) {
System.out.println(" → " + nombre + " notificado: " + mod + " v" + nuevaVersion);
}
}
Participantes: interfaz Observador (suscriptores), interfaz Sujeto (observable), Mod (sujeto
concreto que mantiene la lista y notifica), UsuarioSuscriptor (observador concreto que reacciona).
Al publicarVersion, todos los suscriptores reciben el aviso automáticamente.
