import java.sql.*;
public void registrarPedido(int idProducto, int cantidad, double total) {
String url = "jdbc:mysql://localhost:3306/tienda";
Connection con = null;
try {
con = DriverManager.getConnection(url, "root", "1234");
con.setAutoCommit(false); // INICIO de la transacción
// 1) Insertar el pedido
try (PreparedStatement ps1 = con.prepareStatement(
"INSERT INTO pedido (id_producto, cantidad, total) VALUES (?,?,?)")) {
ps1.setInt(1, idProducto);
ps1.setInt(2, cantidad);
ps1.setDouble(3, total);
ps1.executeUpdate();
}
// 2) Descontar stock
try (PreparedStatement ps2 = con.prepareStatement(
"UPDATE producto SET stock = stock - ? WHERE id = ? AND stock >= ?")) {
ps2.setInt(1, cantidad);
ps2.setInt(2, idProducto);
ps2.setInt(3, cantidad);
int filas = ps2.executeUpdate();
if (filas == 0) throw new SQLException("Stock insuficiente");
}
con.commit(); // CONFIRMA ambas operaciones (todo o nada)
System.out.println("Pedido registrado correctamente.");
} catch (SQLException e) {
try { if (con != null) con.rollback(); } // DESHACE ante cualquier error
catch (SQLException ex) { ex.printStackTrace(); }
System.err.println("Transacción revertida: " + e.getMessage());
} finally {
try { if (con != null) { con.setAutoCommit(true); con.close(); } }
catch (SQLException e) { e.printStackTrace(); }
}
}
commit va al final, tras completar todas las operaciones con éxito (confirma la atomicidad);
rollback va en el catch, para deshacer todo si alguna falla.
